  end else begin : gen_no_gf_mult
    assign calc_mask = '0;

    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        calc_ack <= '0;
      end else if (calc_req && calc_ack) begin
        calc_ack <= '0;
      end else if (calc_req && !calc_ack) begin
        calc_ack <= '1;
